#!/usr/bin/env node

const { execSync } = require('child_process');
const fs = require('fs');
const path = require('path');
const crypto = require('crypto');

const COLORS = {
  reset: '\x1b[0m',
  red: '\x1b[31m',
  green: '\x1b[32m',
  yellow: '\x1b[33m',
  blue: '\x1b[34m',
  cyan: '\x1b[36m',
};

function log(message, color = 'reset') {
  const timestamp = new Date().toISOString();
  console.log(`${COLORS[color]}[${timestamp}] ${message}${COLORS.reset}`);
}

function execStep(command, description, options = {}) {
  log(`▶ ${description}`, 'cyan');
  const startTime = Date.now();
  try {
    const result = execSync(command, {
      stdio: options.silent ? 'pipe' : 'inherit',
      env: { ...process.env, ...options.env },
      timeout: options.timeout || 300000,
      ...options,
    });
    const duration = ((Date.now() - startTime) / 1000).toFixed(2);
    log(`✔ ${description} completed in ${duration}s`, 'green');
    return result ? result.toString().trim() : '';
  } catch (error) {
    const duration = ((Date.now() - startTime) / 1000).toFixed(2);
    log(`✘ ${description} failed after ${duration}s`, 'red');
    if (options.silent && error.stdout) {
      console.error(error.stdout.toString());
    }
    if (options.silent && error.stderr) {
      console.error(error.stderr.toString());
    }
    throw error;
  }
}

function generateSBOM() {
  log('▶ Generating Software Bill of Materials (SBOM)', 'cyan');
  const startTime = Date.now();

  const packageJsonPath = path.resolve('package.json');
  const lockfilePath = path.resolve('package-lock.json');

  if (!fs.existsSync(packageJsonPath)) {
    throw new Error('package.json not found — cannot generate SBOM');
  }

  const packageJson = JSON.parse(fs.readFileSync(packageJsonPath, 'utf-8'));

  const sbom = {
    bomFormat: 'CycloneDX',
    specVersion: '1.4',
    version: 1,
    metadata: {
      timestamp: new Date().toISOString(),
      component: {
        type: 'application',
        name: packageJson.name || 'unknown',
        version: packageJson.version || '0.0.0',
      },
      tools: [
        {
          vendor: 'ci-cd-pipeline',
          name: 'sbom-generator',
          version: '1.0.0',
        },
      ],
    },
    components: [],
  };

  function collectDependencies(deps, scope) {
    if (!deps) return [];
    return Object.entries(deps).map(([name, version]) => ({
      type: 'library',
      name,
      version: version.replace(/^[\^~>=<]/, ''),
      scope,
      purl: `pkg:npm/${name.replace('/', '%2F')}@${version.replace(/^[\^~>=<]/, '')}`,
    }));
  }

  sbom.components.push(
    ...collectDependencies(packageJson.dependencies, 'required'),
    ...collectDependencies(packageJson.devDependencies, 'optional')
  );

  // Enrich with lockfile data for exact resolved versions and integrity hashes
  if (fs.existsSync(lockfilePath)) {
    try {
      const lockfile = JSON.parse(fs.readFileSync(lockfilePath, 'utf-8'));
      const packages = lockfile.packages || lockfile.dependencies || {};

      sbom.components = sbom.components.map((component) => {
        const lockKey =
          `node_modules/${component.name}` in (lockfile.packages || {})
            ? `node_modules/${component.name}`
            : component.name;
        const lockEntry = packages[lockKey];

        if (lockEntry) {
          return {
            ...component,
            version: lockEntry.version || component.version,
            hashes: lockEntry.integrity
              ? [
                  {
                    alg: lockEntry.integrity.startsWith('sha512')
                      ? 'SHA-512'
                      : lockEntry.integrity.startsWith('sha256')
                        ? 'SHA-256'
                        : 'SHA-1',
                    content: lockEntry.integrity.split('-')[1] || lockEntry.integrity,
                  },
                ]
              : [],
            resolved: lockEntry.resolved || undefined,
          };
        }
        return component;
      });
    } catch (e) {
      log(`⚠ Could not parse lockfile for SBOM enrichment: ${e.message}`, 'yellow');
    }
  }

  // Generate a serial number / unique ID for this SBOM
  const sbomContent = JSON.stringify(sbom, null, 2);
  const sbomHash = crypto.createHash('sha256').update(sbomContent).digest('hex');
  sbom.serialNumber = `urn:uuid:${sbomHash.slice(0, 8)}-${sbomHash.slice(8, 12)}-${sbomHash.slice(12, 16)}-${sbomHash.slice(16, 20)}-${sbomHash.slice(20, 32)}`;

  // Write SBOM artifacts
  const sbomDir = path.resolve('sbom');
  if (!fs.existsSync(sbomDir)) {
    fs.mkdirSync(sbomDir, { recursive: true });
  }

  const sbomJsonPath = path.join(sbomDir, 'sbom.json');
  fs.writeFileSync(sbomJsonPath, JSON.stringify(sbom, null, 2));

  // Also write a summary text version
  const summaryLines = [
    `SBOM Summary — ${sbom.metadata.component.name}@${sbom.metadata.component.version}`,
    `Generated: ${sbom.metadata.timestamp}`,
    `Serial: ${sbom.serialNumber}`,
    `Total components: ${sbom.components.length}`,
    '',
    'Components:',
    ...sbom.components.map(
      (c) => `  ${c.scope === 'required' ? '├' : '└'} ${c.name}@${c.version} (${c.scope})`
    ),
  ];
  fs.writeFileSync(path.join(sbomDir, 'sbom-summary.txt'), summaryLines.join('\n'));

  const duration = ((Date.now() - startTime) / 1000).toFixed(2);
  log(`✔ SBOM generated in ${duration}s — ${sbom.components.length} components cataloged`, 'green');
  log(`  SBOM artifact: ${sbomJsonPath}`, 'blue');

  return { sbomPath: sbomJsonPath, componentCount: sbom.components.length, hash: sbomHash };
}

function validateSBOM(sbomPath) {
  log('▶ Validating SBOM artifact', 'cyan');

  if (!fs.existsSync(sbomPath)) {
    throw new Error(`SBOM file not found at ${sbomPath} — deployment blocked`);
  }

  const sbom = JSON.parse(fs.readFileSync(sbomPath, 'utf-8'));

  const requiredFields = ['bomFormat', 'specVersion', 'metadata', 'components'];
  const missingFields = requiredFields.filter((field) => !sbom[field]);

  if (missingFields.length > 0) {
    throw new Error(`SBOM validation failed — missing fields: ${missingFields.join(', ')}`);
  }

  if (!sbom.metadata.timestamp || !sbom.metadata.component) {
    throw new Error('SBOM validation failed — incomplete metadata');
  }

  if (!Array.isArray(sbom.components)) {
    throw new Error('SBOM validation failed — components must be an array');
  }

  // Verify every component has required fields
  const invalidComponents = sbom.components.filter((c) => !c.name || !c.version || !c.type);
  if (invalidComponents.length > 0) {
    throw new Error(
      `SBOM validation failed — ${invalidComponents.length} components missing required fields (name, version, type)`
    );
  }

  // Check SBOM is not stale (must be generated within the last hour)
  const sbomAge = Date.now() - new Date(sbom.metadata.timestamp).getTime();
  const maxAgeMs = 60 * 60 * 1000; // 1 hour
  if (sbomAge > maxAgeMs) {
    throw new Error(
      `SBOM is stale (generated ${(sbomAge / 60000).toFixed(1)} minutes ago) — regenerate before deploying`
    );
  }

  log(`✔ SBOM validation passed — ${sbom.components.length} components verified`, 'green');
  return true;
}

function checkDependencyCache() {
  const lockfilePath = path.resolve('package-lock.json');
  const cacheHashPath = path.resolve('node_modules/.cache-hash');

  if (!fs.existsSync(lockfilePath) || !fs.existsSync('node_modules')) {
    return false;
  }

  if (!fs.existsSync(cacheHashPath)) {
    return false;
  }

  const currentHash = crypto
    .createHash('sha256')
    .update(fs.readFileSync(lockfilePath))
    .digest('hex');
  const cachedHash = fs.readFileSync(cacheHashPath, 'utf-8').trim();

  return currentHash === cachedHash;
}

function saveDependencyCache() {
  const lockfilePath = path.resolve('package-lock.json');
  if (fs.existsSync(lockfilePath)) {
    const hash = crypto
      .createHash('sha256')
      .update(fs.readFileSync(lockfilePath))
      .digest('hex');
    const cacheDir = path.resolve('node_modules/.cache-hash');
    fs.writeFileSync(cacheDir, hash);
  }
}

function detectPackageManager() {
  if (fs.existsSync('pnpm-lock.yaml')) return 'pnpm';
  if (fs.existsSync('yarn.lock')) return 'yarn';
  return 'npm';
}

function detectBuildScript() {
  const packageJson = JSON.parse(fs.readFileSync('package.json', 'utf-8'));
  const scripts = packageJson.scripts || {};
  if (scripts['build:prod']) return 'build:prod';
  if (scripts['build:production']) return 'build:production';
  if (scripts.build) return 'build';
  return null;
}

function detectTestScript() {
  const packageJson = JSON.parse(fs.readFileSync('package.json', 'utf-8'));
  const scripts = packageJson.scripts || {};
  if (scripts['test:ci']) return 'test:ci';
  if (scripts.test) return 'test';
  return null;
}

// ─── Pipeline Configuration ──────────────────────────────────────────────────

const CONFIG = {
  deployTarget: process.env.DEPLOY_TARGET || 'production',
  deployHost: process.env.DEPLOY_HOST || 'deploy.example.com',
  deployPath: process.env.DEPLOY_PATH || '/var/www/app',
  deployUser: process.env.DEPLOY_USER || 'deploy',
  nodeEnv: process.env.NODE_ENV || 'production',
  skipTests: process.env.SKIP_TESTS === 'true',
  skipLint: process.env.SKIP_LINT === 'true',
  dryRun: process.env.DRY_RUN === 'true',
  parallelTests: process.env.PARALLEL_TESTS !== 'false',
  buildArtifactDir: process.env.BUILD_DIR || 'dist',
  maxRetries: parseInt(process.env.MAX_RETRIES || '2', 10),
};

// ─── Pipeline Stages ─────────────────────────────────────────────────────────

async function pipeline() {
  const pipelineStart = Date.now();
  const results = {
    stages: [],
    success: false,
    sbom: null,
  };

  function recordStage(name, fn) {
    const start = Date.now();
    try {
      const result = fn();
      const duration = Date.now() - start;
      results.stages.push({ name, status: 'passed', duration });
      return result;
    } catch (error) {
      const duration = Date.now() - start;
      results.stages.push({ name, status: 'failed', duration, error: error.message });
      throw error;
    }
  }

  try {
    log('═══════════════════════════════════════════════════════════', 'blue');
    log('  CI/CD Pipeline — Rapid Deployment System', 'blue');
    log(`  Target: ${CONFIG.deployTarget} | Dry Run: ${CONFIG.dryRun}`, 'blue');
    log('═══════════════════════════════════════════════════════════', 'blue');

    // ── Stage 1: Environment Validation ──────────────────────────────────

    recordStage('environment-validation', () => {
      log('Stage 1/8: Environment Validation', 'yellow');

      if (!fs.existsSync('package.json')) {
        throw new Error('package.json not found in current directory');
      }

      execStep('node --version', 'Check Node.js version', { silent: true });
      execStep('npm --version', 'Check npm version', { silent: true });

      // Verify required environment for production deploys
      if (CONFIG.deployTarget === 'production' && !CONFIG.dryRun) {
        if (!process.env.DEPLOY_HOST) {
          log('⚠ DEPLOY_HOST not set — using default', 'yellow');
        }
      }
    });

    // ── Stage 2: Dependency Installation (with caching) ──────────────────

    recordStage('install-dependencies', () => {
      log('Stage 2/8: Install Dependencies', 'yellow');

      const pm = detectPackageManager();
      log(`  Detected package manager: ${pm}`, 'blue');

      if (pm === 'npm') {
        if (checkDependencyCache()) {
          log('  ⚡ Dependencies cache hit — skipping install', 'green');
        } else {
          execStep(
            'npm ci --prefer-offline --no-audit --no-fund',
            'Install dependencies (npm ci)',
            { env: { NODE_ENV: 'development' } } // need devDeps for build/test
          );
          saveDependencyCache();
        }
      } else if (pm === 'yarn') {
        execStep('yarn install --frozen-lockfile --non-interactive', 'Install dependencies (yarn)');
      } else if (pm === 'pnpm') {
        execStep('pnpm install --frozen-lockfile', 'Install dependencies (pnpm)');
      }
    });

    // ── Stage 3: SBOM Generation ─────────────────────────────────────────

    recordStage('sbom-generation', () => {
      log('Stage 3/8: SBOM Generation', 'yellow');
      results.sbom = generateSBOM();
    });

    // ── Stage 4: SBOM Validation ─────────────────────────────────────────

    recordStage('sbom-validation', () => {
      log('Stage 4/8: SBOM Validation', 'yellow');

      if (!results.sbom || !results.sbom.sbomPath) {
        throw new Error('SBOM was not generated — cannot proceed with deployment');
      }

      validateSBOM(results.sbom.sbomPath);
    });

    // ── Stage 5: Security Audit ──────────────────────────────────────────

    recordStage('security-audit', () => {
      log('Stage 5/8: Security Audit', 'yellow');

      try {
        execStep('npm audit --production --audit-level=high', 'Dependency security audit', {
          silent: true,
        });
      } catch (e) {
        log('⚠ Security audit found high/critical vulnerabilities — review required', 'yellow');
        // In production, you might want to throw here to block deployment
        if (CONFIG.deployTarget === 'production' && !CONFIG.dryRun) {
          log('  Continuing with warning for production deploy...', 'yellow');
        }
      }
    });

    // ── Stage 6: Linting & Testing ───────────────────────────────────────

    recordStage('lint-and-test', () => {
      log('Stage 6/8: Lint & Test', 'yellow');

      const packageJson = JSON.parse(fs.readFileSync('package.json', 'utf-8'));
      const scripts = packageJson.scripts || {};

      // Linting
      if (!CONFIG.skipLint && scripts.lint) {
        execStep('npm run lint', 'Run linter');
      } else if (CONFIG.skipLint) {
        log('  ⚡ Linting skipped (SKIP_LINT=true)', 'yellow');
      } else {
        log('  ⚡ No lint script found — skipping', 'yellow');
      }

      // Testing
      if (!CONFIG.skipTests) {
        const testScript = detectTestScript();
        if (testScript) {
          const testEnv = {
            NODE_ENV: 'test',
            CI: 'true',
          };
          execStep(`npm run ${testScript}`, 'Run test suite', { env: testEnv });
        } else {
          log('  ⚠ No test script found — skipping tests', 'yellow');
        }
      } else {
        log('  ⚡ Tests skipped (SKIP_TESTS=true)', 'yellow');
      }
    });

    // ── Stage 7: Build ───────────────────────────────────────────────────

    recordStage('build', () => {
      log('Stage 7/8: Build Application', 'yellow');

      const buildScript = detectBuildScript();
      if (buildScript) {
        execStep(`npm run ${buildScript}`, 'Build application', {
          env: { NODE_ENV: CONFIG.nodeEnv },
        });

        // Verify build output exists
        if (!fs.existsSync(CONFIG.buildArtifactDir)) {
          throw new Error(
            `Build artifact directory '${CONFIG.buildArtifactDir}' not found after build`
          );
        }

        // Copy SBOM into build artifacts
        const sbomSource = path.resolve('sbom');
        const sbomDest = path.join(CONFIG.buildArtifactDir, 'sbom');
        if (fs.existsSync(sbomSource)) {
          execStep(`cp -r ${sbomSource} ${sbomDest}`, 'Bundle SBOM with build artifacts');
        }

        // Generate build manifest
        const manifest = {
          buildTime: new Date().toISOString(),
          gitCommit: getGitCommit(),
          gitBranch: getGitBranch(),
          nodeVersion: process.version,
          deployTarget: CONFIG.deployTarget,
          sbomHash: results.sbom ? results.sbom.hash : null,
          sbomComponents: results.sbom ? results.sbom.componentCount : 0,
        };
        fs.writeFileSync(
          path.join(CONFIG.buildArtifactDir, 'build-manifest.json'),
          JSON.stringify(manifest, null, 2)
        );
        log(`  Build manifest written`, 'blue');
      } else {
        log('  ⚠ No build script found — skipping build step', 'yellow');
      }
    });

    // ── Stage 8: Deploy ──────────────────────────────────────────────────

    recordStage('deploy', () => {
      log('Stage 8/8: Deploy to ' + CONFIG.deployTarget, 'yellow');

      // Final SBOM check before deployment — this is the critical gate
      const sbomPath = path.resolve('sbom/sbom.json');
      if (!fs.existsSync(sbomPath)) {
        throw new Error(
          'CRITICAL: SBOM artifact missing before deployment — deployment blocked. ' +
            'An SBOM must be present for every production deployment.'
        );
      }

      // Re-validate freshness
      validateSBOM(sbomPath);
      log('  ✔ SBOM verified present and valid for deployment', 'green');

      if (CONFIG.dryRun) {
        log('  🏁 DRY RUN — skipping actual deployment', 'yellow');
        log(`  Would deploy ${CONFIG.buildArtifactDir}/ to ${CONFIG.deployUser}@${CONFIG.deployHost}:${CONFIG.deployPath}`, 'blue');
        return;
      }

      // Create deployment package
      const deployPackage = `deploy-${Date.now()}.tar.gz`;
      const artifactDir = fs.existsSync(CONFIG.buildArtifactDir)
        ? CONFIG.buildArtifactDir
        : '.';

      execStep(
        `tar -czf ${deployPackage} -C ${artifactDir} . --exclude='node_modules' --exclude='.git'`,
        'Create deployment package'
      );

      // Deploy with retry logic
      let deployed = false;
      for (let attempt = 1; attempt <= CONFIG.maxRetries + 1; attempt++) {
        try {
          log(`  Deploy attempt ${attempt}/${CONFIG.maxRetries + 1}`, 'blue');

          // Upload
          execStep(
            `scp -o StrictHostKeyChecking=no -o ConnectTimeout=30 ${deployPackage} ${CONFIG.deployUser}@${CONFIG.deployHost}:/tmp/${deployPackage}`,
            'Upload deployment package',
            { timeout: 120000 }
          );

          // Extract and restart
          const remoteCommands = [
            `mkdir -p ${CONFIG.deployPath}/releases/$(date +%Y%m%d%H%M%S)`,
            `RELEASE_DIR=${CONFIG.deployPath}/releases/$(date +%Y%m%d%H%M%S)`,
            `tar -xzf /tmp/${deployPackage} -C $RELEASE_DIR`,
            `ln -sfn $RELEASE_DIR ${CONFIG.deployPath}/current`,
            `cd ${CONFIG.deployPath}/current && npm ci --production --prefer-offline 2>/dev/null || true`,
            `rm /tmp/${deployPackage}`,
            // Restart application (PM2 or systemd)
            `cd ${CONFIG.deployPath}/current && (pm2 restart ecosystem.config.js --env production 2>/dev/null || systemctl restart app 2>/dev/null || true)`,
          ].join(' && ');

          execStep(
            `ssh -o StrictHostKeyChecking=no -o ConnectTimeout=30 ${CONFIG.deployUser}@${CONFIG.deployHost} '${remoteCommands}'`,
            'Deploy and restart application',
            { timeout: 180000 }
          );

          deployed = true;
          break;
        } catch (error) {
          if (attempt <= CONFIG.maxRetries) {
            log(`  ⚠ Deploy attempt ${attempt} failed — retrying in 5s...`, 'yellow');
            execSync('sleep 5');
          } else {
            throw new Error(`Deployment failed after ${CONFIG.maxRetries + 1} attempts: ${error.message}`);
          }
        }
      }

      // Cleanup local artifact
      if (fs.existsSync(deployPackage)) {
        fs.unlinkSync(deployPackage);
      }

      if (deployed) {
        log('  🚀 Deployment successful!', 'green');
      }
    });

    results.success = true;
  } catch (error) {
    log(`\n✘ Pipeline failed: ${error.message}`, 'red');
    results.success = false;
  } finally {
    // ── Pipeline Summary ───────────────────────────────────────────────

    const totalDuration = ((Date.now() - pipelineStart) / 1000).toFixed(2);

    log('\n═══════════════════════════════════════════════════════════', 'blue');
    log('  Pipeline Summary', 'blue');
    log('═══════════════════════════════════════════════════════════', 'blue');

    for (const stage of results.stages) {
      const icon = stage.status === 'passed' ? '✔' : '✘';
      const color = stage.status === 'passed' ? 'green' : 'red';
      const duration = (stage.duration / 1000).toFixed(2);
      log(`  ${icon} ${stage.name} (${duration}s)`, color);
      if (stage.error) {
        log(`    Error: ${stage.error}`, 'red');
      }
    }

    if (results.sbom) {
      log(`\n  📋 SBOM: ${results.sbom.componentCount} components | Hash: ${results.sbom.hash.slice(0, 16)}...`, 'blue');
    } else {
      log('\n  ⚠ SBOM: NOT GENERATED — this is a compliance issue', 'red');
    }

    log(`\n  Total time: ${totalDuration}s`, 'blue');
    log(
      `  Result: ${results.success ? '🟢 SUCCESS' : '🔴 FAILED'}`,
      results.success ? 'green' : 'red'
    );
    log('═══════════════════════════════════════════════════════════\n', 'blue');

    // Write pipeline report
    const reportPath = path.resolve('pipeline-report.json');
    fs.writeFileSync(
      reportPath,
      JSON.stringify(
        {
          ...results,
          totalDuration: parseFloat(totalDuration),
          timestamp: new Date().toISOString(),
          config: {
            deployTarget: CONFIG.deployTarget,
            dryRun: CONFIG.dryRun,
            skipTests: CONFIG.skipTests,
          },
        },
        null,
        2
      )
    );

    process.exit(results.success ? 0 : 1);
  }
}

// ─── Utility Helpers ─────────────────────────────────────────────────────────

function getGitCommit() {
  try {
    return execSync('git rev-parse --short HEAD', { stdio: 'pipe' }).toString().trim();
  } catch {
    return 'unknown';
  }
}

function getGitBranch() {
  try {
    return execSync('git rev-parse --abbrev-ref HEAD', { stdio: 'pipe' }).toString().trim();
  } catch {
    return 'unknown';
  }
}

// ─── Entry Point ─────────────────────────────────────────────────────────────

pipeline();